import{_ as a,o as r,c as o,ag as e,ah as s}from"./chunks/framework.D9bIGSBm.js";const u=JSON.parse('{"title":"关于","description":"","frontmatter":{},"headers":[],"relativePath":"settings/about.md","filePath":"settings/about.md"}'),n={name:"settings/about.md"};function d(i,t,l,h,g,c){return r(),o("div",null,[...t[0]||(t[0]=[e('<h1 id="关于" tabindex="-1">关于 <a class="header-anchor" href="#关于" aria-label="Permalink to &quot;关于&quot;">​</a></h1><p><strong>入口：</strong> 侧边栏 → <strong>设置</strong> → <strong>关于</strong>（位于设置侧栏最底部）</p><p>关于页汇总了版本信息、更新检查、用户协议与隐私协议、官方仓库链接、赞助支持与联系方式。</p><p><img src="'+s+'" alt="关于页面，居中显示应用 Logo、名称与当前版本号，下方依次是检查更新、用户协议、隐私协议、官方仓库、赞助支持、联系方式几个条目"></p><hr><h2 id="版本信息与检查更新" tabindex="-1">版本信息与检查更新 <a class="header-anchor" href="#版本信息与检查更新" aria-label="Permalink to &quot;版本信息与检查更新&quot;">​</a></h2><p>页面顶部居中显示应用 Logo、名称与当前版本号（<code>v</code> 前缀 + 版本号）。</p><p><strong>检查更新</strong>行是应用内自动更新的另一个入口（与右上角的更新徽标共用同一套机制，完整流程见<a href="/docs/guide/installation.html#自动更新">安装 → 自动更新</a>），按当前状态显示以下几种样式之一：</p><table tabindex="0"><thead><tr><th>状态</th><th>界面表现</th></tr></thead><tbody><tr><td>默认（未检查）</td><td>显示当前版本号 + <strong>检查更新</strong>按钮</td></tr><tr><td>检查中</td><td>按钮变为<strong>检查中…</strong>（旋转图标），不可重复点击</td></tr><tr><td>已是最新</td><td>手动点击检查后若无新版本，显示绿色「✓ 已是最新版本 · 当前 vX」</td></tr><tr><td>发现新版本，下载中</td><td>显示「发现新版本 vX · 正在后台下载 N%」，下方有下载进度条</td></tr><tr><td>新版本已就绪</td><td>显示「新版本 vX 已就绪」+ <strong>立即重启更新</strong>按钮</td></tr><tr><td>检查失败</td><td>红色「检查更新失败，请检查网络后重试」+ <strong>重试</strong>按钮</td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>应用启动后会自动在后台检查更新，无需手动操作；本行的<strong>检查更新</strong>按钮用于随时手动触发一次检查。</p></div><hr><h2 id="用户协议与隐私协议" tabindex="-1">用户协议与隐私协议 <a class="header-anchor" href="#用户协议与隐私协议" aria-label="Permalink to &quot;用户协议与隐私协议&quot;">​</a></h2><p>点击<strong>用户协议</strong>或<strong>隐私协议</strong>行进入对应的协议明细页，回退按钮与标题同行显示，右上角标注最后更新日期。协议正文随应用当前语言（中/英）自动切换。点击左上角<strong>返回</strong>回到关于页列表。</p><hr><h2 id="官方仓库" tabindex="-1">官方仓库 <a class="header-anchor" href="#官方仓库" aria-label="Permalink to &quot;官方仓库&quot;">​</a></h2><p>点击<strong>官方仓库</strong>行，使用系统默认浏览器打开 LoongCode 的 GitHub 发布仓库。</p><hr><h2 id="赞助支持" tabindex="-1">赞助支持 <a class="header-anchor" href="#赞助支持" aria-label="Permalink to &quot;赞助支持&quot;">​</a></h2><p>点击<strong>赞助支持</strong>行展开手风琴面板，并排显示微信与支付宝收款码，可截图或扫码赞助开发者；再次点击收起。</p><hr><h2 id="联系方式" tabindex="-1">联系方式 <a class="header-anchor" href="#联系方式" aria-label="Permalink to &quot;联系方式&quot;">​</a></h2><p>点击<strong>联系方式</strong>行会把支持邮箱地址复制到剪贴板（不会拉起本机邮件客户端），并弹出「邮箱已复制」提示。</p><hr><h2 id="下一步" tabindex="-1">下一步 <a class="header-anchor" href="#下一步" aria-label="Permalink to &quot;下一步&quot;">​</a></h2><ul><li><a href="/docs/settings/general.html">常规设置</a> — 主题、语言、数据目录等全局配置</li><li><a href="/docs/settings/dependencies.html">依赖管理</a> — 检测与安装 Claude CLI / Codex CLI / OpenCode CLI</li></ul>',25)])])}const b=a(n,[["render",d]]);export{u as __pageData,b as default};
